#include <iostream>
#include <vector>
using namespace std;

bool solve(vector<int>& arr, int maxFreq){
    int n = arr.size();
    for(int i = 0; i < n; i++){
        for(int j = i + 1; j < n; j++)
            if(arr[i] + arr[j] <= maxFreq)
                return true;
    }
    return false;
}

int main(){
    int n, maxFreq;
    cin >> n >> maxFreq;
    vector<int> arr(n);
    for(int i = 0; i < n; i++)
        cin >> arr[i];
    bool result = solve(arr, maxFreq);
    cout << result << endl;
    return 0;
}
